async function saveRoomToDB(roomId, room) {
  try {
    const db = await connectDB();
    const cleanRoom = {
      _id: roomId,
      settings: room.settings,
      players: room.players.map(p => ({
        socketId: p.socketId,
        name: p.name,
        roster: p.roster,
        isOwner: p.isOwner,
        isOnline: p.isOnline
      })),
      draftOrder: room.draftOrder,
