      currentTeam: room.currentTeam,
      blindPool: room.blindPool,
      phase: room.phase,
      evalResult: room.evalResult,
      updatedAt: new Date()
    };
    await db.collection('active_rooms').updateOne(
      { _id: roomId },
      { $set: cleanRoom },
      { upsert: true }
    );
  } catch (err) {
    console.error(`❌ Error saving room ${roomId} to DB:`, err);
  }
}

